arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_6ebcb79b2f574142bff8e19ece51af39.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar" aria-label="Settings sections">
        <h3 class="settings-sidebar-title">Settings</h3>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item">
                    <button class="settings-nav-link @(section.Key == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section.Key)">
                        <span class="settings-nav-icon">@section.Icon</span>
                        <span>@section.Label</span>
                    </button>
                </li>
            }
        </ul>
    </nav>

    <section class="settings-content" aria-live="polite">
        @if (_activeSection == "profile")
        {
            <SettingsProfile />
        }
        else if (_activeSection == "notifications")
        {
            <SettingsNotifications />
        }
        else if (_activeSection == "security")
        {
            <SettingsSecurity />
        }
        else if (_activeSection == "appearance")
        {
            <SettingsAppearance />
        }
    </section>
</div>

@code {
    private string _activeSection = "profile";

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];

    private void SetActiveSection(string key) => _activeSection = key;
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    max-width: 1100px;
    margin: 0 auto;
}

/* Sidebar */
.settings-sidebar {
    min-width: 220px;
    border-right: 1px solid #e0e0e0;
    padding-right: 1.5rem;
}

.settings-sidebar-title {
    font-size: 1.1rem;
    font-weight: 600;
    margin-bottom: 1rem;
    color: #333;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item + .settings-nav-item {
    margin-top: 0.25rem;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    width: 100%;
    padding: 0.65rem 1rem;
    border: none;
    border-radius: 0.5rem;
    background: transparent;
    color: #555;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.settings-nav-link:hover {
    background: #f0f0f0;
    color: #111;
}

.settings-nav-link.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

/* Shared section styles */
.settings-section-title {
    font-size: 1.4rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
    color: #222;
}

.settings-section-desc {
    color: #666;
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
}

.settings-card {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 0.75rem;
    padding: 1.5rem;
    margin-bottom: 1.25rem;
}

.settings-card-title {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 1rem;
    color: #333;
}

/* Form elements */
.settings-field {
    margin-bottom: 1rem;
}

.settings-field label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
    color: #444;
}

.settings-field input[type="text"],
.settings-field input[type="email"],
.settings-field input[type="password"],
.settings-field textarea,
.settings-field select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d1d5db;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    transition: border-color 0.15s;
}

.settings-field input:focus,
.settings-field textarea:focus,
.settings-field select:focus {
    outline: none;
    border-color: #0d6efd;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

.settings-field textarea {
    resize: vertical;
    min-height: 80px;
}

/* Buttons */
.btn-settings-primary {
    padding: 0.5rem 1.25rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-primary:hover {
    background: #0b5ed7;
}

.btn-settings-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-settings-secondary {
    padding: 0.5rem 1.25rem;
    background: transparent;
    color: #555;
    border: 1px solid #d1d5db;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-secondary:hover {
    background: #f3f4f6;
}

.btn-settings-danger {
    padding: 0.35rem 0.85rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-danger:hover {
    background: #bb2d3b;
}

.settings-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

/* Toggle switch */
.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.65rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-row-label {
    font-size: 0.9rem;
    color: #333;
}

.toggle-switch {
    position: relative;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    inset: 0;
    background: #ccc;
    border-radius: 24px;
    cursor: pointer;
    transition: background 0.2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform 0.2s;
}

.toggle-switch input:checked + .toggle-slider {
    background: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(20px);
}

/* Toast message */
.settings-toast {
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.875rem;
    margin-bottom: 1rem;
    animation: toast-in 0.3s ease;
}

.settings-toast.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.settings-toast.error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-8px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* Avatar preview */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1rem;
}

.avatar-preview img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #e5e7eb;
}

.avatar-url {
    font-size: 0.8rem;
    color: #888;
    word-break: break-all;
}

/* Expandable panel */
.expandable-panel {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    overflow: hidden;
    margin-bottom: 1rem;
}

.expandable-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    background: #f9fafb;
    border: none;
    width: 100%;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
    color: #333;
}

.expandable-header:hover {
