                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn-settings-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span style="font-size:0.8rem; color:#0d6efd;">Current</span>
                                }
