/* Sidebar */
.settings-sidebar {
    min-width: 220px;
    border-right: 1px solid #e0e0e0;
    padding-right: 1.5rem;
}

.settings-sidebar-title {
    font-size: 1.1rem;
    font-weight: 600;
    margin-bottom: 1rem;
    color: #333;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item + .settings-nav-item {
    margin-top: 0.25rem;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    width: 100%;
    padding: 0.65rem 1rem;
    border: none;
    border-radius: 0.5rem;
    background: transparent;
    color: #555;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}

.settings-nav-link:hover {
    background: #f0f0f0;
    color: #111;
}

.settings-nav-link.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

/* Shared section styles */
.settings-section-title {
    font-size: 1.4rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
    color: #222;
}

.settings-section-desc {
    color: #666;
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
}

.settings-card {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 0.75rem;
    padding: 1.5rem;
    margin-bottom: 1.25rem;
}

.settings-card-title {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 1rem;
    color: #333;
}

/* Form elements */
.settings-field {
    margin-bottom: 1rem;
}

.settings-field label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
    color: #444;
}

.settings-field input[type="text"],
.settings-field input[type="email"],
.settings-field input[type="password"],
.settings-field textarea,
.settings-field select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d1d5db;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    transition: border-color 0.15s;
}

.settings-field input:focus,
.settings-field textarea:focus,
.settings-field select:focus {
    outline: none;
    border-color: #0d6efd;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.15);
}

.settings-field textarea {
    resize: vertical;
    min-height: 80px;
}

/* Buttons */
.btn-settings-primary {
    padding: 0.5rem 1.25rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-primary:hover {
    background: #0b5ed7;
}

.btn-settings-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-settings-secondary {
    padding: 0.5rem 1.25rem;
    background: transparent;
    color: #555;
    border: 1px solid #d1d5db;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-secondary:hover {
    background: #f3f4f6;
}

.btn-settings-danger {
    padding: 0.35rem 0.85rem;
    background: #dc3545;
    color: #fff;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-settings-danger:hover {
    background: #bb2d3b;
}

.settings-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

/* Toggle switch */
.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.65rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-row-label {
    font-size: 0.9rem;
    color: #333;
}

.toggle-switch {
    position: relative;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    inset: 0;
    background: #ccc;
    border-radius: 24px;
    cursor: pointer;
    transition: background 0.2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform 0.2s;
}

.toggle-switch input:checked + .toggle-slider {
    background: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(20px);
}

/* Toast message */
.settings-toast {
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.875rem;
    margin-bottom: 1rem;
    animation: toast-in 0.3s ease;
}

.settings-toast.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.settings-toast.error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-8px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* Avatar preview */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1rem;
}

.avatar-preview img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #e5e7eb;
}

.avatar-url {
    font-size: 0.8rem;
    color: #888;
    word-break: break-all;
}

/* Expandable panel */
.expandable-panel {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    overflow: hidden;
    margin-bottom: 1rem;
}

.expandable-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    background: #f9fafb;
    border: none;
    width: 100%;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
    color: #333;
}

.expandable-header:hover {
    background: #f3f4f6;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #e5e7eb;
}

/* Session table */
.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.875rem;
}

.sessions-table th {
    text-align: left;
    padding: 0.5rem 0.75rem;
    border-bottom: 2px solid #e5e7eb;
    font-weight: 600;
    color: #555;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.sessions-table td {
    padding: 0.6rem 0.75rem;
    border-bottom: 1px solid #f0f0f0;
    color: #333;
}

/* Status indicator */
.status-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.85rem;
    padding: 0.25rem 0.6rem;
    border-radius: 1rem;
    font-weight: 500;
}

.status-badge.enabled {
    background: #d1e7dd;
    color: #0f5132;
}

.status-badge.disabled {
    background: #f8d7da;
    color: #842029;
}

/* Channel list */
.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.45rem 0;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

.channel-item label {
    font-size: 0.9rem;
    color: #444;
    cursor: pointer;
}

/* Radio group */
.radio-group {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.4rem;
}

.radio-option input[type="radio"] {
    accent-color: #0d6efd;
}

.radio-option label {
    font-size: 0.9rem;
    color: #444;
    cursor: pointer;
}

/* Live preview */
.appearance-preview {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-top: 1rem;
    transition: all 0.3s ease;
}

.appearance-preview.dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.appearance-preview.light {
    background: #ffffff;
    color: #333;
}

.appearance-preview.compact .preview-line {
    margin-bottom: 0.25rem;
}

.appearance-preview .preview-line {
    margin-bottom: 0.5rem;
}

.appearance-preview .preview-title {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

/* Confirmation dialog overlay */
.confirm-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    animation: fade-in 0.15s ease;
}

.confirm-dialog {
    background: #fff;
    border-radius: 0.75rem;
    padding: 1.5rem;
    min-width: 340px;
    max-width: 440px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.15);
}

.confirm-dialog h4 {
    margin: 0 0 0.5rem;
    font-size: 1.05rem;
}

.confirm-dialog p {
    color: #666;
    font-size: 0.9rem;
    margin-bottom: 1.25rem;
}

.confirm-actions {
    display: flex;
    gap: 0.75rem;
    justify-content: flex-end;
}

@keyframes fade-in {
    from { opacity: 0; }
    to   { opacity: 1; }
}

/* Loading */
.settings-loading {
    padding: 2rem;
    text-align: center;
    color: #888;
    font-size: 0.9rem;
}

@using sv_6ebcb79b2f574142bff8e19ece51af39.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="settings-loading">Loading profile…</div>
}
else
{
    <h2 class="settings-section-title">Profile</h2>
    <p class="settings-section-desc">Manage your personal information and public profile.</p>

    @if (_toast is not null)
    {
        <div class="settings-toast @_toast.Css">@_toast.Message</div>
    }

    <div class="settings-card">
        <div class="avatar-preview">
            <img src="@_avatarUrl" alt="Avatar preview" />
            <span class="avatar-url">@_avatarUrl</span>
        </div>

        <div class="settings-field">
            <label for="profile-avatar">Avatar URL</label>
            <input id="profile-avatar" type="text" @bind="_avatarUrl" />
        </div>

        <div class="settings-field">
            <label for="profile-name">Display Name</label>
            <input id="profile-name" type="text" @bind="_displayName" />
        </div>

        <div class="settings-field">
            <label for="profile-email">Email</label>
            <input id="profile-email" type="email" @bind="_email" />
        </div>

        <div class="settings-field">
            <label for="profile-bio">Bio</label>
            <textarea id="profile-bio" @bind="_bio"></textarea>
        </div>

        <div class="settings-actions">
            <button class="btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn-settings-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private ToastMessage? _toast;

    private record ToastMessage(string Message, string Css);

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _toast = new("Profile saved successfully.", "success");
        }
        catch
        {
            _toast = new("Failed to save profile.", "error");
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _toast = null;
    }
}

@using sv_6ebcb79b2f574142bff8e19ece51af39.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="settings-loading">Loading notifications…</div>
}
else
{
    <h2 class="settings-section-title">Notifications</h2>
    <p class="settings-section-desc">Control how and when you receive notifications.</p>

    @if (_toast is not null)
    {
        <div class="settings-toast @_toast.Css">@_toast.Message</div>
    }

    <div class="settings-card">
        <div class="settings-card-title">Notification Channels</div>

        <div class="toggle-row">
            <span class="toggle-row-label">Email Notifications</span>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_emailNotifications" />
                <span class="toggle-slider"></span>
            </label>
        </div>

        <div class="toggle-row">
            <span class="toggle-row-label">Push Notifications</span>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_pushNotifications" />
                <span class="toggle-slider"></span>
            </label>
        </div>

        <div class="toggle-row">
            <span class="toggle-row-label">Weekly Digest</span>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_weeklyDigest" />
                <span class="toggle-slider"></span>
            </label>
        </div>
    </div>

    <div class="settings-card">
        <div class="settings-card-title">Muted Channels</div>
        <p class="settings-section-desc" style="margin-bottom:0.75rem">
            Checked channels are muted and will not send notifications.
        </p>

        <ul class="channel-list">
            @foreach (var channel in _allChannels)
            {
                var ch = channel;
                <li class="channel-item">
                    <input type="checkbox" id="ch-@ch"
                           checked="@_mutedChannels.Contains(ch)"
                           @onchange="e => ToggleMute(ch, (bool)(e.Value ?? false))" />
                    <label for="ch-@ch">#@ch</label>
                </li>
            }
        </ul>
    </div>

    <div class="settings-actions">
        <button class="btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;

    private readonly HashSet<string> _mutedChannels = [];
    private static readonly List<string> _allChannels =
        ["general", "engineering", "marketing", "random", "announcements", "design"];

    private record ToastMessage(string Message, string Css);
    private ToastMessage? _toast;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;

        _mutedChannels.Clear();
        foreach (var c in prefs.MutedChannels) _mutedChannels.Add(c);

        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _toast = new("Notification preferences saved.", "success");
        }
        catch
        {
            _toast = new("Failed to save preferences.", "error");
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_6ebcb79b2f574142bff8e19ece51af39.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="settings-loading">Loading security settings…</div>
}
else
{
    <h2 class="settings-section-title">Security</h2>
    <p class="settings-section-desc">Manage your password, two-factor authentication, and active sessions.</p>

    @if (_toast is not null)
    {
        <div class="settings-toast @_toast.Css">@_toast.Message</div>
    }

    <!-- Change Password expandable panel -->
    <div class="expandable-panel">
        <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>🔑 Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </button>

        @if (_passwordPanelOpen)
        {
            <div class="expandable-body">
                <div class="settings-field">
                    <label for="sec-current-pw">Current Password</label>
                    <input id="sec-current-pw" type="password" @bind="_currentPassword" />
                </div>
                <div class="settings-field">
                    <label for="sec-new-pw">New Password</label>
                    <input id="sec-new-pw" type="password" @bind="_newPassword" />
                </div>
                <div class="settings-field">
                    <label for="sec-confirm-pw">Confirm New Password</label>
                    <input id="sec-confirm-pw" type="password" @bind="_confirmPassword" />
                </div>

                @if (_passwordError is not null)
                {
                    <div class="settings-toast error" style="margin-top:0.5rem">@_passwordError</div>
                }

                <div class="settings-actions">
                    <button class="btn-settings-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="settings-card">
        <div class="settings-card-title">Two-Factor Authentication</div>
        <div class="toggle-row">
            <div>
                <span class="toggle-row-label">Two-factor authentication</span>
                <br />
                <span class="status-badge @(_twoFactorEnabled ? "enabled" : "disabled")">
                    @(_twoFactorEnabled ? "✓ Enabled" : "✗ Disabled")
                </span>
            </div>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_twoFactorEnabled" />
                <span class="toggle-slider"></span>
            </label>
        </div>
        @if (_lastPasswordChange.HasValue)
        {
            <p style="font-size:0.8rem; color:#888; margin-top:0.75rem;">
                Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="settings-card">
        <div class="settings-card-title">Active Sessions</div>

        @if (_sessions.Count == 0)
        {
            <p style="color:#888; font-size:0.9rem;">No active sessions found.</p>
        }
        else
        {
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn-settings-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span style="font-size:0.8rem; color:#0d6efd;">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>

    <!-- Revoke confirmation dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="confirm-overlay" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation="true">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong>
                   in @_sessionToRevoke.Location? The user will be signed out immediately.</p>
                <div class="confirm-actions">
                    <button class="btn-settings-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn-settings-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;

    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;

    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;

    // Treat the first session as "current"
    private string? _currentSessionId;

    private record ToastMessage(string Message, string Css);
    private ToastMessage? _toast;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _currentSessionId = _sessions.FirstOrDefault()?.Id;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _toast = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _toast = new("Password updated successfully.", "success");
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _lastPasswordChange = DateTime.UtcNow;
        }
        catch
        {
            _toast = new("Failed to change password.", "error");
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _toast = new($"Session on {_sessionToRevoke.Device} revoked.", "success");
        }
        catch
        {
            _toast = new("Failed to revoke session.", "error");
        }
        finally
        {
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

