{"file_text": "@using sv_6ebcb79b2f574142bff8e19ece51af39.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="settings-loading">Loading appearance settings…</div>
}
else
{
    <h2 class="settings-section-title">Appearance</h2>
    <p class="settings-section-desc">Customize the look and feel of your application.</p>

    @if (_toast is not null)
    {
        <div class="settings-toast @_toast.Css">@_toast.Message</div>
    }

    <div class="settings-card">
        <div class="settings-card-title">Theme</div>
        <div class="radio-group">
            @foreach (var theme in _themes)
            {
                var t = theme;
                <div class="radio-option">
                    <input type="radio" id="theme-@t" name="theme"
                           value="@t"
                           checked="@(_theme == t)"
                           @onchange="() => _theme = t" />
                    <label for="theme-@t">@t</label>
                </div>
            }
        </div>
    </div>

    <div class="settings-card">
        <div class="settings-card-title">Font Size</div>
        <div class="radio-group">
            @foreach (var size in _fontSizes)
            {
                var s = size;
                <div class="radio-option">
                    <input type="radio" id="font-@s" name="fontSize"
                           value="@s"
                           checked="@(_fontSize == s)"
                           @onchange="() => _fontSize = s" />
                    <label for="font-@s">@s</label>
                </div>
            }
        </div>
    </div>

    <div class="settings-card">
        <div class="settings-card-title">Language</div>
        <div class="settings-field" style="margin-bottom:0">
            <select @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>
    </div>

    <div class="settings-card">
        <div class="toggle-row" style="border:none">
            <span class="toggle-row-label">Compact Mode</span>
            <label class="toggle-switch">
                <input type="checkbox" @bind="_compactMode" />
                <span class="toggle-slider"></span>
            </label>
        </div>
    </div>

    <!-- Live preview -->
    <div class="settings-card">
        <div class="settings-card-title">Preview</div>
        <div class="appearance-preview @PreviewThemeClass @(_compactMode ? "compact" : "")"
             style="font-size: @PreviewFontSize">
            <div class="preview-title">Sample Dashboard</div>
            <div class="preview-line">Theme: @_theme | Font: @_fontSize | Language: @_language</div>
            <div class="preview-line">This is how your content will look with the selected settings.</div>
            <div class="preview-line">
                <span style="opacity:0.7">
                    Compact mode is @(_compactMode ? "on — tighter spacing" : "off — normal spacing").
                </span>
            </div>
        </div>
    </div>

    <div class="settings-actions">
        <button class="btn-settings-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private record ToastMessage(string Message, string Css);
    private ToastMessage? _toast;

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "dark",
        "Light" => "light",
        _ => "" // System: no extra class
    };

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.8rem",
        "Large" => "1.1rem",
        _ => "0.95rem"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toast = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _toast = new("Appearance settings saved.", "success");
        }
        catch
        {
            _toast = new("Failed to save appearance settings.", "error");
        }
        finally
        {
            _saving = false;
        }
    }
}
