+.radio-group {
+    display: flex;
+    gap: 1rem;
+    flex-wrap: wrap;
+}
+
+.radio-option {
+    display: flex;
+    align-items: center;
+    gap: 0.4rem;
+}
+
+.radio-option input[type="radio"] {
+    accent-color: #0d6efd;
+}
+
+.radio-option label {
+    font-size: 0.9rem;
+    color: #444;
+    cursor: pointer;
+}
+
+/* Live preview */
+.appearance-preview {
+    border: 1px solid #e5e7eb;
+    border-radius: 0.5rem;
+    padding: 1.25rem;
+    margin-top: 1rem;
+    transition: all 0.3s ease;
+}
+
+.appearance-preview.dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.appearance-preview.light {
+    background: #ffffff;
+    color: #333;
+}
+
+.appearance-preview.compact .preview-line {
+    margin-bottom: 0.25rem;
+}
+
+.appearance-preview .preview-line {
+    margin-bottom: 0.5rem;
+}
+
+.appearance-preview .preview-title {
+    font-weight: 600;
+    margin-bottom: 0.5rem;
+}
+
+/* Confirmation dialog overlay */
+.confirm-overlay {
+    position: fixed;
+    inset: 0;
+    background: rgba(0, 0, 0, 0.4);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1000;
+    animation: fade-in 0.15s ease;
+}
+
+.confirm-dialog {
+    background: #fff;
+    border-radius: 0.75rem;
+    padding: 1.5rem;
+    min-width: 340px;
+    max-width: 440px;
+    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.15);
+}
+
+.confirm-dialog h4 {
+    margin: 0 0 0.5rem;
+    font-size: 1.05rem;
+}
+
+.confirm-dialog p {
+    color: #666;
+    font-size: 0.9rem;
+    margin-bottom: 1.25rem;
+}
+
+.confirm-actions {
+    display: flex;
+    gap: 0.75rem;
+    justify-content: flex-end;
+}
+
+@keyframes fade-in {
+    from { opacity: 0; }
+    to   { opacity: 1; }
+}
+
+/* Loading */
+.settings-loading {
+    padding: 2rem;
+    text-align: center;
+    color: #888;
+    font-size: 0.9rem;
+}
+

